foreach($groups as $group) {
    $groupName = $group['name'];
    $domain = $group['domain'];
    $slogan = $group['slogan'];
    $members = $group['members'];
    
    if(!is_dir($groupName)) mkdir($groupName, 0777, true);
    if(!is_dir("$groupName/members")) mkdir("$groupName/members", 0777, true);
    
    // Create db.php
    $dbContent = "<?php\n\$host = 'localhost';\n\$dbname = '{$groupName}_db';\n\$user = '{$groupName}_user';\n\$pass = 'Pass2026!';\n\ntry {\n    \$pdo = new PDO(\"mysql:host=\$host;dbname=\$dbname\", \$user, \$pass);\n    \$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);\n} catch(PDOException \$e) {\n    die(\"Connection failed: \" . \$e->getMessage());\n}\n?>\n";
    file_put_contents("$groupName/db.php", $dbContent);
    
    // Create index.php
    $indexContent = "<?php require_once 'db.php'; ?>\n<!DOCTYPE html>\n<html>\n<head>\n    <title>" . ucfirst($groupName) . "</title>\n    <style>\n        body { font-family: Arial, sans-serif; max-width: 1000px; margin: 50px auto; padding: 20px; background: #f4f4f4; }\n        h1 { color: #333; }\n        .slogan { color: #666; font-style: italic; margin-bottom: 30px; }\n        table { width: 100%; border-collapse: collapse; background: white; }\n        th, td { padding: 12px; text-align: left; border-bottom: 1px solid #ddd; }\n        th { background: #4CAF50; color: white; }\n    </style>\n</head>\n<body>\n    <h1>" . ucfirst($groupName) . "</h1>\n    <p><strong>Domain:</strong> $domain</p>\n    <p class=\"slogan\">\"$slogan\"</p>\n    <h2>Our Team Members</h2>\n    <table>\n        <tr><th>Name</th><th>Registration Number</th><th>Role</th><th>Subdomain</th></tr>\n        <?php\n        \$stmt = \$pdo->query(\"SELECT * FROM members ORDER BY id\");\n        while(\$row = \$stmt->fetch(PDO::FETCH_ASSOC)) {\n            echo \"<tr><td>{\$row['name']}</td><td>{\$row['registration_number']}</td><td>{\$row['role']}</td><td>{\$row['subdomain']}</td></tr>\";\n        }\n        ?>\n    </table>\n</body>\n</html>\n";
    file_put_contents("$groupName/index.php", $indexContent);
    
    // Create schema.sql
    $schemaContent = "CREATE DATABASE IF NOT EXISTS {$groupName}_db;\nCREATE USER IF NOT EXISTS '{$groupName}_user'@'localhost' IDENTIFIED BY 'Pass2026!';\nGRANT ALL PRIVILEGES ON {$groupName}_db.* TO '{$groupName}_user'@'localhost';\nFLUSH PRIVILEGES;\n\nUSE {$groupName}_db;\n\nCREATE TABLE IF NOT EXISTS members (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    registration_number VARCHAR(50) NOT NULL,\n    role VARCHAR(100) NOT NULL,\n    subdomain VARCHAR(100) NOT NULL\n);\n\nINSERT INTO members (name, registration_number, role, subdomain) VALUES\n";
    $insertValues = [];
    foreach($members as $idx => $member) {
        $regNum = 'REG' . str_pad($idx + 1, 3, '0', STR_PAD_LEFT);
        $insertValues[] = "('" . ucfirst($member) . "', '$regNum', 'Developer', '$member.$domain')";
    }
    $schemaContent .= implode(",\n", $insertValues) . ";\n";
    file_put_contents("$groupName/schema.sql", $schemaContent);
    
    // Create member subdomain pages
    foreach($members as $member) {
